package pe.org.camaracomercioica.protestos.security;
import com.fasterxml.jackson.databind.ObjectMapper; import jakarta.servlet.http.*; import lombok.RequiredArgsConstructor; import org.springframework.http.MediaType; import org.springframework.security.access.AccessDeniedException; import org.springframework.security.core.AuthenticationException; import org.springframework.security.web.AuthenticationEntryPoint; import org.springframework.security.web.access.AccessDeniedHandler; import org.springframework.stereotype.Component; import pe.org.camaracomercioica.protestos.exception.ApiError; import java.io.IOException; import java.time.Instant; import java.util.Map;
@Component @RequiredArgsConstructor public class SecurityErrorHandler implements AuthenticationEntryPoint,AccessDeniedHandler {private final ObjectMapper mapper;@Override public void commence(HttpServletRequest request,HttpServletResponse response,AuthenticationException exception)throws IOException{write(request,response,401,"UNAUTHORIZED","Autenticación requerida");}@Override public void handle(HttpServletRequest request,HttpServletResponse response,AccessDeniedException exception)throws IOException{write(request,response,403,"FORBIDDEN","No tiene permisos para esta operación");}private void write(HttpServletRequest req,HttpServletResponse res,int status,String code,String message)throws IOException{res.setStatus(status);res.setContentType(MediaType.APPLICATION_JSON_VALUE);mapper.writeValue(res.getOutputStream(),new ApiError(Instant.now(),status,code,message,req.getRequestURI(),Map.of()));}}
